const navbar=document.getElementById("ebhdr3-hdr"),toggle=document.getElementById("ebhdr3-navToggle"),overlay=document.getElementById("ebhdr3-navMenu"),navClose=document.getElementById("ebhdr3-navClose");toggle.addEventListener("click",()=>{navbar.classList.toggle("ebhdr3-nav--open")}),navClose.addEventListener("click",()=>{navbar.classList.remove("ebhdr3-nav--open")}),document.addEventListener("click",e=>{navbar.contains(e.target)&&"ebhdr3-navMenu"!=e.target.id||navbar.classList.remove("ebhdr3-nav--open")}),window.addEventListener("scroll",()=>{window.scrollY>50?navbar.classList.add("ebhdr3-nav--scrolled"):navbar.classList.remove("ebhdr3-nav--scrolled")});